const date = $json.query.date;
const clean = (date || '').replace(/-/g, '');

return [{
  json: {
    range: JSON.stringify({
      start: `${clean}T000000Z`,
      end: `${clean}T235959Z`,
    }),
  },
}];

const body = $input.first().json;
const events = body.events || body.Events || [];

function toLocalHeure(value) {
  // Format attendu : yyyyMMddTHHmmssZ (UTC)
  const match = String(value).match(/T(\d{2})(\d{2})/);
  if (!match) return null;
  let hour = parseInt(match[1], 10);
  const minute = match[2];
  hour = (hour + 2) % 24; // UTC -> heure de Paris (UTC+2 en ete)
  return `${hour.toString().padStart(2, '0')}:${minute}`;
}

const appointments = [];
for (const ev of events) {
  if (ev.fbtype && String(ev.fbtype).toLowerCase() !== 'busy') continue;
  const start = ev.startTime || ev.starttime || (ev.dateandtime && ev.dateandtime.start);
  const heure = start ? toLocalHeure(start) : null;
  if (heure) appointments.push({ heure });
}

return [{ json: { appointments } }];
